namespace sv_c885c7cf5df3417a90f2f04052dbd19c.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public record ThemeInfo(Theme Theme, string AccentColor)
{
    public static ThemeInfo Default => new(Theme.Light, "#0d6efd");
}

using Microsoft.AspNetCore.Components;

namespace sv_c885c7cf5df3417a90f2f04052dbd19c.Services;

/// <summary>
/// Scoped service that holds mutable theme state for a single circuit.
/// Mutations push updates to all [CascadingParameter] subscribers via
/// the injected CascadingValueSource.
/// </summary>
public class ThemeService
{
    private readonly CascadingValueSource<ThemeInfo> _source;

    public ThemeService(CascadingValueSource<ThemeInfo> source)
    {
        _source = source;
    }

    public ThemeInfo Current { get; private set; } = ThemeInfo.Default;

    public event Action? OnChange;

    public async Task SetThemeAsync(Theme theme)
    {
        Current = Current with { Theme = theme };
        await NotifyAsync();
    }

    public async Task SetAccentColorAsync(string color)
    {
        Current = Current with { AccentColor = color };
        await NotifyAsync();
    }

    public async Task SetAllAsync(Theme theme, string accentColor)
    {
        Current = new ThemeInfo(theme, accentColor);
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        await _source.NotifyChangedAsync(Current);
        OnChange?.Invoke();
    }
}

