arguments.file_text:
@inject Services.ThemeService ThemeService
@implements IDisposable

<span class="theme-indicator" style="color: @Theme?.AccentColor;">
    @GetIcon() @Theme?.Theme
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    private string GetIcon() => Theme?.Theme switch
    {
        Services.Theme.Dark => "🌙",
        Services.Theme.System => "💻",
        _ => "☀️"
    };

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject Services.ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h3>User Preferences</h3>

<div class="mb-3">
    <label class="form-label fw-bold">Theme</label>
    <div class="btn-group d-block" role="group">
        @foreach (var t in Enum.GetValues<Services.Theme>())
        {
            <button class="btn @(t == CurrentTheme ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => SetTheme(t)">
                @t
            </button>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label fw-bold">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@CurrentAccent"
           @onchange="SetAccentColor" />
</div>

<p style="color: @CurrentAccent;">
    Preview: current accent is <strong>@CurrentAccent</strong>, theme is <strong>@CurrentTheme</strong>.
</p>

@code {
    private Services.Theme CurrentTheme => ThemeService.Current.Theme;
    private string CurrentAccent => ThemeService.Current.AccentColor;

    [CascadingParameter]
    private Services.ThemeInfo? Theme { get; set; }

    private async Task SetTheme(Services.Theme theme)
    {
        await ThemeService.SetThemeAsync(theme);
    }

    private async Task SetAccentColor(ChangeEventArgs e)
    {
        await ThemeService.SetAccentColorAsync(e.Value?.ToString() ?? "#0d6efd");
    }
}

